export const wwwwJs = `
import app from '../app.ts';
import debugLib from 'debug';
import http from 'http';

type xError = {
    syscall:string
    code:string
}

const debug = debugLib('site:server');

const port = normalizePort(process.env.PORT || '3000');
app.set('port', port);

const server = http.createServer(app);

server.listen(port);
server.on('error', onError);
server.on('listening', onListening);


console.log('Listening on port: 3000');


function normalizePort(val:string) {
    const port = parseInt(val, 10);

    if (isNaN(port)) {
    return val;
    }

    if (port >= 0) {
    return port;
    }

    return false;
}

function onError(error:xError) {
    if (error.syscall !== 'listen') {
    throw error;
    }

    const bind = typeof port === 'string'
    ? 'Pipe ' + port
    : 'Port ' + port;

    switch (error.code) {
    case 'EACCES':
        console.error(bind + ' requires elevated privileges');
        process.exit(1);
        break;
    case 'EADDRINUSE':
        console.error(bind + ' is already in use');
        process.exit(1);
        break;
    default:
        throw error;
    }
}

function onListening() {
    const addr = server.address();
    const bind = typeof addr === 'string'
    ? 'pipe ' + addr
    : 'port ' + addr?.port;
    debug('Listening on ' + bind);
}
`

export const appTs = `
import { DbConnect } from './db/db.ts'
import createError from 'http-errors';
import express from 'express';
import path from 'path';
import { fileURLToPath } from 'url';
import cookieParser from 'cookie-parser';
import logger from 'morgan';
import cors from 'cors'

import indexRouter from './routes/index.ts';

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const app = express();

// view engine setup
// app.set('views', path.join(__dirname, 'views'));
// app.set('view engine', 'html');

app.use(cors({
    origin:"localhost:5173" // local reactapp
}))

app.use(logger('dev'));
app.use(express.json());
app.use(express.urlencoded({ extended: false }));
app.use(cookieParser());
app.use(express.static(path.join(__dirname, 'public')));

app.use('/', indexRouter);

// catch 404 and forward to error handler
app.use(function(req, res, next) {
    next(createError(404));
});

// setup connection DbConnect()

// error handler
app.use((err: { message: string; status?: number }, req: express.Request, res: express.Response, _next: express.NextFunction) => {
    res.locals.message = err.message;
    res.locals.error = req.app.get('env') === 'development' ? err : {};

    res.status(err.status || 500);
});

export default app;

`;

